/**
 * Overlay Data Slice
 *
 * State management for canvas overlay panels: man-hours and drift analysis.
 * These overlays provide actionable insights on top of the PM schedule canvas.
 *
 * @see specs/006-user-interface.md Section 6.4.3
 */

import { createSlice } from '@belt/tools';

// =============================================================================
// Man-Hour Overlay Types
// =============================================================================

export type ManhourStatus = 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';

export interface ManhourAdjustment {
  type: string;
  hours: number;
  status: string;
}

export interface DepotManhourData {
  depotId: string;
  depotCode: string;
  requiredHours: number;
  availableHours: number;
  utilizationPct: number;
  status: ManhourStatus;
  adjustments: ManhourAdjustment[];
}

export interface ManhourWeekData {
  weekStart: string;
  depots: DepotManhourData[];
}

export interface ManhourOverlayData {
  weeks: ManhourWeekData[];
}

// =============================================================================
// Drift Overlay Types
// =============================================================================

export type DriftSeverity = 'GREEN' | 'YELLOW' | 'RED';

export interface PmDrift {
  pmId: string;
  driftDays: number;
}

export interface TrainDriftData {
  trainId: string;
  trainNumber: string;
  driftSeverity: DriftSeverity;
  mileageDriftPct: number;
  pmDrifts: PmDrift[];
}

export interface DriftOverlayData {
  baselineId: string;
  baselineName: string;
  trains: TrainDriftData[];
}

export interface DriftRecommendation {
  trainId: string;
  trainNumber: string;
  recommendation: 'REPLAN' | 'MONITOR' | 'OK';
  reason: string;
  priority: 'HIGH' | 'MEDIUM' | 'LOW';
}

// =============================================================================
// Overlay State
// =============================================================================

export interface OverlaySliceState {
  // Man-hour overlay
  manhourData: ManhourOverlayData | null;
  manhourLoading: boolean;
  manhourError: string | null;
  manhourLastFetch: number | null;
  manhourWeeks: number;
  manhourDepotFilter: string | null;
  manhourExpandedWeeks: string[];

  // Drift overlay
  driftData: DriftOverlayData | null;
  driftLoading: boolean;
  driftError: string | null;
  driftLastFetch: number | null;
  driftBaselineId: string | null;
  driftSeverityFilter: DriftSeverity | null;
  driftExpandedTrains: string[];
  driftRecommendations: DriftRecommendation[];

  // Panel state
  manhourPanelExpanded: boolean;
  driftPanelExpanded: boolean;

  [key: string]: unknown;
}

const initialOverlayState: OverlaySliceState = {
  // Man-hour overlay
  manhourData: null,
  manhourLoading: false,
  manhourError: null,
  manhourLastFetch: null,
  manhourWeeks: 12,
  manhourDepotFilter: null,
  manhourExpandedWeeks: [],

  // Drift overlay
  driftData: null,
  driftLoading: false,
  driftError: null,
  driftLastFetch: null,
  driftBaselineId: null,
  driftSeverityFilter: null,
  driftExpandedTrains: [],
  driftRecommendations: [],

  // Panel state
  manhourPanelExpanded: true,
  driftPanelExpanded: true,
};

export const overlaySlice = createSlice({
  id: 'overlay',
  initial: initialOverlayState,
  cache: { policy: 'session' },
  reducers: {
    // ==========================================================================
    // Man-hour Overlay Reducers
    // ==========================================================================

    setManhourLoading: (s, loading: boolean) => {
      const state = s as OverlaySliceState;
      state.manhourLoading = loading;
    },

    setManhourData: (s, data: ManhourOverlayData) => {
      const state = s as OverlaySliceState;
      state.manhourData = data;
      state.manhourLoading = false;
      state.manhourError = null;
      state.manhourLastFetch = Date.now();
    },

    setManhourError: (s, error: string) => {
      const state = s as OverlaySliceState;
      state.manhourError = error;
      state.manhourLoading = false;
    },

    clearManhourData: (s) => {
      const state = s as OverlaySliceState;
      state.manhourData = null;
      state.manhourError = null;
      state.manhourLastFetch = null;
    },

    setManhourWeeks: (s, weeks: number) => {
      const state = s as OverlaySliceState;
      state.manhourWeeks = weeks;
    },

    setManhourDepotFilter: (s, depotId: string | null) => {
      const state = s as OverlaySliceState;
      state.manhourDepotFilter = depotId;
    },

    expandManhourWeek: (s, weekStart: string) => {
      const state = s as OverlaySliceState;
      if (!state.manhourExpandedWeeks.includes(weekStart)) {
        state.manhourExpandedWeeks.push(weekStart);
      }
    },

    collapseManhourWeek: (s, weekStart: string) => {
      const state = s as OverlaySliceState;
      state.manhourExpandedWeeks = state.manhourExpandedWeeks.filter(w => w !== weekStart);
    },

    toggleManhourWeek: (s, weekStart: string) => {
      const state = s as OverlaySliceState;
      if (state.manhourExpandedWeeks.includes(weekStart)) {
        state.manhourExpandedWeeks = state.manhourExpandedWeeks.filter(w => w !== weekStart);
      } else {
        state.manhourExpandedWeeks.push(weekStart);
      }
    },

    toggleManhourPanel: (s) => {
      const state = s as OverlaySliceState;
      state.manhourPanelExpanded = !state.manhourPanelExpanded;
    },

    // ==========================================================================
    // Drift Overlay Reducers
    // ==========================================================================

    setDriftLoading: (s, loading: boolean) => {
      const state = s as OverlaySliceState;
      state.driftLoading = loading;
    },

    setDriftData: (s, data: DriftOverlayData) => {
      const state = s as OverlaySliceState;
      state.driftData = data;
      state.driftLoading = false;
      state.driftError = null;
      state.driftLastFetch = Date.now();

      // Generate recommendations based on drift data
      state.driftRecommendations = data.trains
        .filter(t => t.driftSeverity !== 'GREEN')
        .map(train => ({
          trainId: train.trainId,
          trainNumber: train.trainNumber,
          recommendation: train.driftSeverity === 'RED' ? 'REPLAN' as const : 'MONITOR' as const,
          reason: train.driftSeverity === 'RED'
            ? `Mileage drift of ${Math.abs(train.mileageDriftPct).toFixed(1)}% exceeds threshold`
            : `Mileage drift approaching threshold at ${Math.abs(train.mileageDriftPct).toFixed(1)}%`,
          priority: train.driftSeverity === 'RED' ? 'HIGH' as const : 'MEDIUM' as const,
        }));
    },

    setDriftError: (s, error: string) => {
      const state = s as OverlaySliceState;
      state.driftError = error;
      state.driftLoading = false;
    },

    clearDriftData: (s) => {
      const state = s as OverlaySliceState;
      state.driftData = null;
      state.driftError = null;
      state.driftLastFetch = null;
      state.driftRecommendations = [];
    },

    setDriftBaselineId: (s, baselineId: string | null) => {
      const state = s as OverlaySliceState;
      state.driftBaselineId = baselineId;
    },

    setDriftSeverityFilter: (s, severity: DriftSeverity | null) => {
      const state = s as OverlaySliceState;
      state.driftSeverityFilter = severity;
    },

    expandDriftTrain: (s, trainId: string) => {
      const state = s as OverlaySliceState;
      if (!state.driftExpandedTrains.includes(trainId)) {
        state.driftExpandedTrains.push(trainId);
      }
    },

    collapseDriftTrain: (s, trainId: string) => {
      const state = s as OverlaySliceState;
      state.driftExpandedTrains = state.driftExpandedTrains.filter(t => t !== trainId);
    },

    toggleDriftTrain: (s, trainId: string) => {
      const state = s as OverlaySliceState;
      if (state.driftExpandedTrains.includes(trainId)) {
        state.driftExpandedTrains = state.driftExpandedTrains.filter(t => t !== trainId);
      } else {
        state.driftExpandedTrains.push(trainId);
      }
    },

    toggleDriftPanel: (s) => {
      const state = s as OverlaySliceState;
      state.driftPanelExpanded = !state.driftPanelExpanded;
    },

    // ==========================================================================
    // General Reducers
    // ==========================================================================

    reset: (s) => {
      const state = s as OverlaySliceState;
      Object.assign(state, initialOverlayState);
    },
  },
});

// =============================================================================
// Data Loading Functions
// =============================================================================

/**
 * Load man-hour overlay data from API
 */
export async function loadManhourOverlayData(
  dispatch: {
    setManhourLoading: (loading: boolean) => void;
    setManhourData: (data: ManhourOverlayData) => void;
    setManhourError: (error: string) => void;
  },
  options: { baseUrl?: string; weeks?: number; depotId?: string } = {}
): Promise<void> {
  const { baseUrl = '/api/v1', weeks = 12, depotId } = options;

  dispatch.setManhourLoading(true);

  const params = new URLSearchParams();
  params.set('weeks', String(weeks));
  if (depotId) {
    params.set('depotId', depotId);
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/manhour-overlay?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch man-hour overlay: ${response.status}`);
    }

    const json = await response.json() as { data: ManhourOverlayData };
    dispatch.setManhourData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setManhourError(message);
  }
}

/**
 * Load drift overlay data from API
 */
export async function loadDriftOverlayData(
  dispatch: {
    setDriftLoading: (loading: boolean) => void;
    setDriftData: (data: DriftOverlayData) => void;
    setDriftError: (error: string) => void;
  },
  options: { baseUrl?: string; baselineId?: string } = {}
): Promise<void> {
  const { baseUrl = '/api/v1', baselineId } = options;

  dispatch.setDriftLoading(true);

  const params = new URLSearchParams();
  if (baselineId) {
    params.set('baselineId', baselineId);
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/drift-overlay?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch drift overlay: ${response.status}`);
    }

    const json = await response.json() as { data: DriftOverlayData };
    dispatch.setDriftData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setDriftError(message);
  }
}

// =============================================================================
// Selectors
// =============================================================================

/**
 * Get filtered man-hour weeks based on depot filter
 */
export function selectFilteredManhourWeeks(state: OverlaySliceState): ManhourWeekData[] {
  if (!state.manhourData) return [];

  if (!state.manhourDepotFilter) {
    return state.manhourData.weeks;
  }

  return state.manhourData.weeks.map(week => ({
    ...week,
    depots: week.depots.filter(d => d.depotId === state.manhourDepotFilter),
  }));
}

/**
 * Get weeks with overloaded status
 */
export function selectOverloadedWeeks(state: OverlaySliceState): ManhourWeekData[] {
  if (!state.manhourData) return [];

  return state.manhourData.weeks.filter(week =>
    week.depots.some(d => d.status === 'OVERLOADED')
  );
}

/**
 * Get total overloaded hours across all weeks
 */
export function selectTotalOverloadedHours(state: OverlaySliceState): number {
  if (!state.manhourData) return 0;

  return state.manhourData.weeks.reduce((total, week) => {
    return total + week.depots.reduce((weekTotal, depot) => {
      if (depot.status === 'OVERLOADED') {
        return weekTotal + (depot.requiredHours - depot.availableHours);
      }
      return weekTotal;
    }, 0);
  }, 0);
}

/**
 * Get filtered trains based on drift severity filter
 */
export function selectFilteredDriftTrains(state: OverlaySliceState): TrainDriftData[] {
  if (!state.driftData) return [];

  if (!state.driftSeverityFilter) {
    return state.driftData.trains;
  }

  return state.driftData.trains.filter(t => t.driftSeverity === state.driftSeverityFilter);
}

/**
 * Get trains requiring replan (RED severity)
 */
export function selectTrainsRequiringReplan(state: OverlaySliceState): TrainDriftData[] {
  if (!state.driftData) return [];
  return state.driftData.trains.filter(t => t.driftSeverity === 'RED');
}

/**
 * Get drift summary statistics
 */
export function selectDriftSummaryStats(state: OverlaySliceState): {
  totalTrains: number;
  greenCount: number;
  yellowCount: number;
  redCount: number;
} {
  if (!state.driftData) {
    return { totalTrains: 0, greenCount: 0, yellowCount: 0, redCount: 0 };
  }

  const trains = state.driftData.trains;
  return {
    totalTrains: trains.length,
    greenCount: trains.filter(t => t.driftSeverity === 'GREEN').length,
    yellowCount: trains.filter(t => t.driftSeverity === 'YELLOW').length,
    redCount: trains.filter(t => t.driftSeverity === 'RED').length,
  };
}

/**
 * Check if man-hour data is stale (>5 minutes)
 */
export function isManhourDataStale(state: OverlaySliceState): boolean {
  if (!state.manhourLastFetch) return true;
  return Date.now() - state.manhourLastFetch > 5 * 60 * 1000;
}

/**
 * Check if drift data is stale (>5 minutes)
 */
export function isDriftDataStale(state: OverlaySliceState): boolean {
  if (!state.driftLastFetch) return true;
  return Date.now() - state.driftLastFetch > 5 * 60 * 1000;
}

