/**
 * Baseline Management Routes
 *
 * REST endpoints for plan baseline management.
 * Baselines are immutable snapshots of the PM schedule and mileage projections
 * used for drift analysis and scenario comparison.
 *
 * @see specs/005-api.md Section 5.8
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getBaselineService,
  type BaselineListFilters,
  type BaselineStatus,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let baselineService: ReturnType<typeof getBaselineService> | null = null;

function getService(): ReturnType<typeof getBaselineService> {
  if (!baselineService) {
    baselineService = getBaselineService();
  }
  return baselineService;
}

export const baselineRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /baselines
 *
 * List plan baselines with filtering and pagination.
 *
 * Query Parameters:
 * - status: Filter by status (DRAFT, PUBLISHED, SUPERSEDED, ARCHIVED)
 * - fromDate: Filter by baseline date (ISO date)
 * - toDate: Filter by baseline date (ISO date)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 20, max: 100)
 * - sort: Sort field (baselineDate:asc, createdAt:desc, etc.)
 */
baselineRoutes.get('/baselines', async (c) => {
  const service = getService();

  // Parse query filters
  const filters: BaselineListFilters = {};
  const status = c.req.query('status');
  const fromDate = c.req.query('fromDate');
  const toDate = c.req.query('toDate');

  if (status) {
    const validStatuses: BaselineStatus[] = ['DRAFT', 'PUBLISHED', 'SUPERSEDED', 'ARCHIVED'];
    const statusValues = status.split(',').filter((s) => validStatuses.includes(s as BaselineStatus));
    if (statusValues.length === 1) {
      filters.status = statusValues[0] as BaselineStatus;
    } else if (statusValues.length > 1) {
      filters.status = statusValues as BaselineStatus[];
    }
  }

  if (fromDate) {
    const parsed = new Date(fromDate);
    if (!isNaN(parsed.getTime())) {
      filters.fromDate = parsed;
    }
  }

  if (toDate) {
    const parsed = new Date(toDate);
    if (!isNaN(parsed.getTime())) {
      filters.toDate = parsed;
    }
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sort'),
  });

  const result = await service.listBaselines(filters, {
    page: pagination.page,
    pageSize: Math.min(pagination.pageSize, 100), // Cap at 100 for baselines
    sortBy: pagination.sort?.field as 'baselineDate' | 'createdAt' | 'version' | undefined,
    sortOrder: pagination.sort?.direction,
  });

  // Map to API response format per spec 005.8
  const baselines = result.data.map((baseline) => ({
    id: baseline.id,
    name: baseline.name,
    version: baseline.version,
    description: baseline.description,
    baselineDate: baseline.baselineDate,
    horizonEnd: baseline.horizonEnd,
    status: baseline.status,
    publishedAt: baseline.publishedAt,
    publishedBy: baseline.publishedBy
      ? { id: baseline.publishedBy, displayName: null } // Would need user lookup for displayName
      : null,
    metrics: {
      fleetCount: baseline.fleetCount,
      totalPMScheduled: baseline.totalPmScheduled,
      totalManhoursProjected: baseline.totalManhourProjected
        ? parseFloat(baseline.totalManhourProjected)
        : null,
    },
    createdAt: baseline.createdAt,
  }));

  return c.json(
    paginatedSuccess(
      baselines,
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /baselines/latest
 *
 * Get the most recent published baseline.
 * Convenience endpoint for common use case.
 */
baselineRoutes.get('/baselines/latest', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  const baseline = await service.getLatestBaseline();

  if (!baseline) {
    return c.json(error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId), 404);
  }

  return c.json(
    success(
      {
        id: baseline.id,
        name: baseline.name,
        version: baseline.version,
        description: baseline.description,
        baselineDate: baseline.baselineDate,
        horizonEnd: baseline.horizonEnd,
        status: baseline.status,
        publishedAt: baseline.publishedAt,
        metrics: {
          fleetCount: baseline.fleetCount,
          totalPMScheduled: baseline.totalPmScheduled,
          totalManhoursProjected: baseline.totalManhourProjected
            ? parseFloat(baseline.totalManhourProjected)
            : null,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /baselines/:id
 *
 * Get baseline details by ID.
 */
baselineRoutes.get('/baselines/:id', async (c) => {
  const requestId = getRequestId(c);
  const baselineId = c.req.param('id');

  if (!isValidUuid(baselineId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId), 400);
  }

  const service = getService();
  const baseline = await service.getBaselineById(baselineId);

  return c.json(
    success(
      {
        id: baseline.id,
        name: baseline.name,
        version: baseline.version,
        description: baseline.description,
        baselineDate: baseline.baselineDate,
        horizonEnd: baseline.horizonEnd,
        status: baseline.status,
        publishedAt: baseline.publishedAt,
        publishedBy: baseline.publishedBy
          ? { id: baseline.publishedBy, displayName: null }
          : null,
        supersededBy: baseline.supersededBy,
        supersededAt: baseline.supersededAt,
        metrics: {
          fleetCount: baseline.fleetCount,
          totalPMScheduled: baseline.totalPmScheduled,
          totalManhoursProjected: baseline.totalManhourProjected
            ? parseFloat(baseline.totalManhourProjected)
            : null,
        },
        createdAt: baseline.createdAt,
        createdBy: baseline.createdBy,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * POST /baselines
 *
 * Publish a new baseline from the current plan state.
 *
 * The baseline will:
 * 1. Validate the current plan for critical conflicts
 * 2. Snapshot the current PM schedule
 * 3. Generate mileage projections
 * 4. Supersede any previous published baseline
 *
 * Request body:
 * - name: Baseline name (required)
 * - description: Optional description
 * - horizonYears: Projection horizon in years (default: 10)
 */
baselineRoutes.post('/baselines', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  // Validate required fields
  if (!body.name || typeof body.name !== 'string' || body.name.trim().length === 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Baseline name is required', requestId),
      400
    );
  }

  // Get user from context (or fallback for development)
  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  const baseline = await service.publishBaseline({
    name: body.name.trim(),
    description: body.description?.trim(),
    userId,
    horizonYears: body.horizonYears ? Number(body.horizonYears) : undefined,
  });

  return c.json(
    success(
      {
        id: baseline.id,
        name: baseline.name,
        version: baseline.version,
        description: baseline.description,
        baselineDate: baseline.baselineDate,
        horizonEnd: baseline.horizonEnd,
        status: baseline.status,
        publishedAt: baseline.publishedAt,
        metrics: {
          fleetCount: baseline.fleetCount,
          totalPMScheduled: baseline.totalPmScheduled,
          totalManhoursProjected: baseline.totalManhourProjected
            ? parseFloat(baseline.totalManhourProjected)
            : null,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    ),
    201
  );
});

/**
 * GET /baselines/:id/pm-schedule
 *
 * Get the PM schedule snapshot for a baseline.
 *
 * Query Parameters:
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 100, max: 500)
 */
baselineRoutes.get('/baselines/:id/pm-schedule', async (c) => {
  const requestId = getRequestId(c);
  const baselineId = c.req.param('id');

  if (!isValidUuid(baselineId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId), 400);
  }

  const page = c.req.query('page') ? Number(c.req.query('page')) : 1;
  const pageSize = Math.min(c.req.query('pageSize') ? Number(c.req.query('pageSize')) : 100, 500);

  const service = getService();
  const result = await service.getBaselinePmSchedule(baselineId, { page, pageSize });

  // Map to API response format
  const pmSchedule = result.data.map((item) => ({
    id: item.id,
    trainId: item.trainId,
    pmTypeId: item.pmTypeId,
    projectedDate: item.projectedDate,
    projectedMileageKm: item.projectedMileageKm,
    assignedDepotId: item.assignedDepotId,
    assignedHours: item.assignedHours ? parseFloat(item.assignedHours) : null,
  }));

  return c.json(
    paginatedSuccess(
      pmSchedule,
      {
        page,
        pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /baselines/:id/mileage-projections
 *
 * Get mileage projections for a baseline.
 *
 * Query Parameters:
 * - trainId: Filter by specific train (UUID)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 100, max: 500)
 */
baselineRoutes.get('/baselines/:id/mileage-projections', async (c) => {
  const requestId = getRequestId(c);
  const baselineId = c.req.param('id');

  if (!isValidUuid(baselineId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId), 400);
  }

  const trainId = c.req.query('trainId');
  if (trainId && !isValidUuid(trainId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId), 400);
  }

  const page = c.req.query('page') ? Number(c.req.query('page')) : 1;
  const pageSize = Math.min(c.req.query('pageSize') ? Number(c.req.query('pageSize')) : 100, 500);

  const service = getService();
  const result = await service.getMileageProjections(baselineId, trainId, { page, pageSize });

  // Map to API response format
  const projections = result.data.map((item) => ({
    id: item.id,
    trainId: item.trainId,
    projectionDate: item.projectionDate,
    projectedCumulativeKm: item.projectedCumulativeKm,
    dailyRateKm: item.dailyRateKm,
  }));

  return c.json(
    paginatedSuccess(
      projections,
      {
        page,
        pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /baselines/:id/summary
 *
 * Get baseline summary statistics.
 * Convenience endpoint for dashboard display.
 */
baselineRoutes.get('/baselines/:id/summary', async (c) => {
  const requestId = getRequestId(c);
  const baselineId = c.req.param('id');

  if (!isValidUuid(baselineId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId), 400);
  }

  const service = getService();
  const summary = await service.getBaselineSummary(baselineId);

  return c.json(
    success(summary, { timing: { durationMs: getRequestDuration(c) } })
  );
});

/**
 * POST /baselines/:id/archive
 *
 * Archive a superseded baseline.
 * Archived baselines are retained for audit purposes but excluded from normal queries.
 *
 * Note: Cannot archive PUBLISHED baselines - must publish a new baseline first.
 */
baselineRoutes.post('/baselines/:id/archive', async (c) => {
  const requestId = getRequestId(c);
  const baselineId = c.req.param('id');

  if (!isValidUuid(baselineId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId), 400);
  }

  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  const baseline = await service.archiveBaseline(baselineId, userId);

  return c.json(
    success(
      {
        id: baseline.id,
        name: baseline.name,
        version: baseline.version,
        status: baseline.status,
        archivedAt: new Date().toISOString(),
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

