   892→export async function loadStrategicData(
   893→  dispatch: {
   894→    setStrategicLoading: (loading: boolean) => void;
   895→    setStrategicData: (data: StrategicCanvasData) => void;
   896→    setStrategicError: (error: string) => void;
   897→  },
   898→  options: { baseUrl?: string; fromYear?: number; toYear?: number; fleetId?: string } = {}
   899→): Promise<void> {
   900→  const {
   901→    baseUrl = '/api/v1',
   902→    fromYear = new Date().getFullYear(),
   903→    toYear = new Date().getFullYear() + 10,
   904→    fleetId,
