  1083→export async function loadDetailData(
  1084→  dispatch: {
  1085→    setDetailLoading: (loading: boolean) => void;
  1086→    setDetailData: (data: DetailCanvasData) => void;
  1087→    setDetailError: (error: string) => void;
  1088→  },
  1089→  options: { baseUrl?: string; fromDate?: string; toDate?: string; trainIds?: string[] } = {}
  1090→): Promise<void> {
  1091→  const {
  1092→    baseUrl = '/api/v1',
  1093→    fromDate,
  1094→    toDate,
  1095→    trainIds,
  1096→  } = options;
  1097→
  1098→  dispatch.setDetailLoading(true);
  1099→
  1100→  const params = new URLSearchParams();
  1101→  if (fromDate) {
  1102→    params.set('fromDate', fromDate);
  1103→  }
  1104→  if (toDate) {
  1105→    params.set('toDate', toDate);
  1106→  }
  1107→  if (trainIds && trainIds.length > 0) {
  1108→    params.set('trainIds', trainIds.join(','));
  1109→  }
  1110→
  1111→  try {
  1112→    const response = await fetch(`${baseUrl}/canvas/detail?${params}`);
  1113→
