  1115→      throw new Error(`Failed to fetch detail data: ${response.status}`);
  1116→    }
  1117→
  1118→    const json = (await response.json()) as { data: DetailCanvasData };
  1119→    dispatch.setDetailData(json.data);
  1120→  } catch (error) {
