     1→/**
     2→ * MMS Infinite Canvas
     3→ *
     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→ *
     7→ * Zoom Level Rendering:
     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→ * - DETAIL (16+): React DOM overlay
    13→ *
    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→ */
    16→
    17→import { useRef } from 'react';
    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';
    19→
    20→import { useCanvas, useCanvasData, useFleet, usePm, useUi, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→import type { PmSliceState } from '../../store/slices/pm';
    25→import type { UiSliceState } from '../../store/slices/ui';
    26→import type { ZoomLevel } from '../../store/types';
    27→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
    28→import { DragConfirmationDialog } from './DragConfirmationDialog';
    29→import { quickValidatePmMove, createDebouncedValidation, getPmMoveImpact, commitPmMove, createCanvasKeyboardHandler, type KeyboardHandlerCallbacks } from './utils';
    30→import { KeyboardShortcutsDialog } from '../KeyboardShortcutsDialog';
    31→
    32→// Toaster helper for showing notifications
    33→// Uses the static show method which handles async creation
    34→async function showToast(options: {
    35→  intent: typeof Intent[keyof typeof Intent];
    36→  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
    37→  message: string;
    38→  timeout: number;
    39→}): Promise<void> {
    40→  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
    41→  toaster.show(options);
    42→}
    43→
    44→/** Default canvas dimensions when container size is not available */
    45→const DEFAULT_CANVAS_WIDTH = 1200;
    46→const DEFAULT_CANVAS_HEIGHT = 800;
    47→
    48→// Drag confirmation state interface
    49→interface DragConfirmState {
    50→  isOpen: boolean;
    51→  pmId: string | null;
    52→  pmCode: string;
    53→  trainNumber: string;
    54→  sourceDate: string;
    55→  targetDate: string;
    56→  impact: PmMoveImpact | null;
    57→  isLoadingImpact: boolean;
    58→}
    59→
    60→const initialDragConfirmState: DragConfirmState = {
    61→  isOpen: false,
    62→  pmId: null,
    63→  pmCode: '',
    64→  trainNumber: '',
    65→  sourceDate: '',
    66→  targetDate: '',
    67→  impact: null,
    68→  isLoadingImpact: false,
    69→};
    70→
    71→export function InfiniteCanvas() {
    72→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    73→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    74→  const { state: fleetStateRaw } = useFleet();
    75→  const { state: pmStateRaw, actions: pmActions } = usePm();
    76→  const { state: uiStateRaw, actions: uiActions } = useUi();
    77→
    78→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    79→  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
    80→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
    81→  const pmState = pmStateRaw as unknown as PmSliceState;
    82→  const uiState = uiStateRaw as unknown as UiSliceState;
    83→
    84→  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
    85→  const {
    86→    strategicData, strategicLoading, strategicError, fromYear, toYear,
    87→    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
    88→    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
    89→    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
    90→    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
    91→  } = canvasDataState;
    92→  const isLoading = fleetState.trains.length === 0;
    93→
    94→  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
    95→  const tooltipRef = useRef<HTMLDivElement>(null);
    96→
    97→  // Drag state refs
    98→  const dragValidationRef = useRef<DragValidationState | null>(null);
    99→  const draggingPmRef = useRef<{
   100→    pmId: string;
   101→    pmCode: string;
   102→    trainId: string;
   103→    trainNumber: string;
   104→    sourceDate: string;
   105→    constraintStart: string;
   106→    constraintEnd: string;
   107→    isLocked: boolean;
   108→  } | null>(null);
   109→  const dragConfirmRef = useRef<DragConfirmState>(initialDragConfirmState);
   110→
   111→  // Create debounced API validation
   112→  const debouncedValidationRef = useRef(
   113→    createDebouncedValidation((result) => {
   114→      dragValidationRef.current = result;
   115→      if (draggingPmRef.current) {
   116→        pmActions.setDragValidation({
   117→          isValid: result.isValid,
   118→          message: result.message,
   119→          violations: result.violations,
   120→        });
   121→      }
   122→    }, { delay: 150 })
   123→  );
   124→
   125→  // Ref for container to handle focus
   126→  const containerRef = useRef<HTMLDivElement>(null);
   127→
   128→  // ==========================================================================
   129→  // Keyboard Handler Callbacks
   130→  // ==========================================================================
   131→
   132→  const keyboardCallbacksRef = useRef<KeyboardHandlerCallbacks>({
   133→    // Navigation
   134→    onPan: (direction, amount) => {
   135→      const delta = { dx: 0, dy: 0 };
   136→      switch (direction) {
   137→        case 'up':
   138→          delta.dy = -amount;
   139→          break;
   140→        case 'down':
   141→          delta.dy = amount;
   142→          break;
   143→        case 'left':
