   779→/**
   780→ * GET /canvas/detail
   781→ *
   782→ * Get detail-level canvas data with full PM information.
   783→ * Used for the detail view (zoom 16+) with rich editing capabilities.
   784→ * Includes change history, constraint validation, and crew assignments.
   785→ *
   786→ * Query Parameters:
   787→ * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
   788→ * - fromDate: Start date (ISO date, defaults to start of current week)
   789→ * - toDate: End date (ISO date, defaults to +1 week)
   790→ *
   791→ * @see specs/006-user-interface.md Section 6.3.4, 6.3.5 (Detail zoom level 16+)
   792→ */
   793→canvasRoutes.get('/canvas/detail', async (c) => {
   794→  const requestId = getRequestId(c);
   795→
   796→  const trainIdsParam = c.req.query('trainIds');
   797→  const fromDateParam = c.req.query('fromDate');
   798→  const toDateParam = c.req.query('toDate');
   799→
   800→  const trainIds = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];
   801→
   802→  for (const id of trainIds) {
   803→    if (!isValidUuid(id)) {
   804→      return c.json(
   805→        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
   806→        400
   807→      );
   808→    }
   809→  }
   810→
   811→  // Default to 1 week starting from current week (for detailed view)
   812→  const today = new Date();
   813→  const defaultFromDate = new Date(today);
   814→  defaultFromDate.setDate(today.getDate() - today.getDay()); // Start of week
   815→  const defaultToDate = new Date(defaultFromDate);
   816→  defaultToDate.setDate(defaultToDate.getDate() + 7); // 1 week ahead
   817→
   818→  let fromDate: Date;
   819→  let toDate: Date;
   820→
   821→  if (fromDateParam) {
   822→    fromDate = new Date(fromDateParam);
   823→    if (isNaN(fromDate.getTime())) {
   824→      return c.json(
   825→        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format', requestId),
   826→        400
   827→      );
   828→    }
   829→  } else {
   830→    fromDate = defaultFromDate;
   831→  }
   832→
   833→  if (toDateParam) {
   834→    toDate = new Date(toDateParam);
   835→    if (isNaN(toDate.getTime())) {
   836→      return c.json(
   837→        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format', requestId),
   838→        400
   839→      );
   840→    }
   841→  } else {
   842→    toDate = defaultToDate;
   843→  }
   844→
   845→  const fromDateStr = fromDate.toISOString().split('T')[0];
   846→  const toDateStr = toDate.toISOString().split('T')[0];
   847→
   848→  // Fetch PM blocks with detailed information
   849→  const pmConditions = [
   850→    gte(pmSchedule.targetDate, fromDateStr),
   851→    lte(pmSchedule.targetDate, toDateStr),
   852→    isNull(pmSchedule.scenarioId),
   853→  ];
   854→
   855→  if (trainIds.length > 0) {
   856→    pmConditions.push(inArray(pmSchedule.trainId, trainIds));
   857→  }
   858→
   859→  const pmResults = await db
   860→    .select({
   861→      pmId: pmSchedule.id,
   862→      trainId: pmSchedule.trainId,
   863→      trainNumber: trains.trainNumber,
   864→      fleetCode: fleets.code,
   865→      pmCode: pmTypes.pmCode,
   866→      pmName: pmTypes.pmName,
   867→      targetDate: pmSchedule.targetDate,
   868→      status: pmSchedule.status,
   869→      constraintStart: pmSchedule.constraintStart,
   870→      constraintEnd: pmSchedule.constraintEnd,
   871→      isLocked: pmSchedule.isLocked,
   872→      trackNumber: tracks.trackNumber,
   873→      depotCode: depots.code,
   874→      displayColor: pmTypes.displayColor,
   875→      estimatedHours: pmTypes.estimatedHours,
   876→      minTrackDays: pmTypes.minTrackDays,
   877→      assignedShift: pmSchedule.assignedShift,
   878→      createdAt: pmSchedule.createdAt,
   879→      updatedAt: pmSchedule.updatedAt,
   880→    })
   881→    .from(pmSchedule)
   882→    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   883→    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
   884→    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
   885→    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
   886→    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
   887→    .where(and(...pmConditions))
   888→    .orderBy(pmSchedule.targetDate);
   889→
   890→  // Transform PM blocks with full detail information
   891→  const pmBlocks = pmResults.map((row) => {
   892→    const durationDays = row.minTrackDays ?? 1;
   893→    const targetDate = new Date(row.targetDate);
   894→    const endDate = new Date(targetDate);
   895→    endDate.setDate(targetDate.getDate() + durationDays - 1);
   896→
   897→    // Mock change history (in production, this would come from audit trail)
   898→    type ChangeHistoryChangeType = 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
   899→    const changeHistory: Array<{
   900→      id: string;
   901→      timestamp: string;
   902→      changeType: ChangeHistoryChangeType;
   903→      userId: string;
   904→      userName: string;
   905→      reason?: string;
   906→    }> = [
   907→      {
   908→        id: `${row.pmId}-create`,
   909→        timestamp: row.createdAt?.toISOString() ?? new Date().toISOString(),
   910→        changeType: 'CREATE',
   911→        userId: 'system',
   912→        userName: 'System',
   913→        reason: 'Initial PM scheduling',
   914→      },
   915→    ];
   916→
   917→    // Add update entry if updatedAt differs from createdAt
   918→    if (row.updatedAt && row.createdAt && row.updatedAt.getTime() !== row.createdAt.getTime()) {
   919→      changeHistory.push({
   920→        id: `${row.pmId}-update`,
   921→        timestamp: row.updatedAt.toISOString(),
   922→        changeType: 'MOVE',
   923→        userId: 'system',
   924→        userName: 'System',
   925→        reason: 'PM updated',
   926→      });
   927→    }
   928→
   929→    // Calculate constraint validation
   930→    const today = new Date();
   931→    today.setHours(0, 0, 0, 0);
   932→    const constraintEnd = new Date(row.constraintEnd);
   933→    const daysToDeadline = Math.floor((constraintEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   934→
   935→    const violations: Array<{
   936→      type: 'HARD' | 'SOFT';
   937→      constraint: string;
   938→      message: string;
   939→      canOverride: boolean;
   940→    }> = [];
   941→
   942→    const warnings: Array<{
   943→      type: string;
   944→      message: string;
   945→    }> = [];
   946→
   947→    if (daysToDeadline < 0) {
   948→      violations.push({
   949→        type: 'HARD',
   950→        constraint: 'Compliance Window',
   951→        message: `PM is ${Math.abs(daysToDeadline)} days past compliance deadline`,
   952→        canOverride: false,
   953→      });
   954→    } else if (daysToDeadline < 7) {
   955→      warnings.push({
   956→        type: 'COMPLIANCE_WARNING',
   957→        message: `Compliance window closes in ${daysToDeadline} days`,
   958→      });
   959→    }
   960→
   961→    return {
   962→      pmId: row.pmId,
   963→      trainId: row.trainId,
   964→      trainNumber: row.trainNumber,
   965→      fleetCode: row.fleetCode,
   966→      pmCode: row.pmCode,
   967→      pmDescription: row.pmName ?? row.pmCode,
   968→      targetDate: row.targetDate,
   969→      endDate: endDate.toISOString().split('T')[0],
   970→      durationDays,
   971→      status: row.status,
   972→      constraintStart: row.constraintStart,
   973→      constraintEnd: row.constraintEnd,
   974→      isLocked: row.isLocked ?? false,
   975→      trackNumber: row.trackNumber,
   976→      depotCode: row.depotCode,
   977→      estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
   978→      assignedShift: row.assignedShift,
   979→      // Material requirements - empty for now, can be populated from inventory integration
   980→      materials: [] as Array<{
   981→        materialId: string;
   982→        materialName: string;
   983→        quantityRequired: number;
   984→        quantityAvailable: number;
   985→        status: 'AVAILABLE' | 'LOW_STOCK' | 'UNAVAILABLE' | 'ARRIVING';
   986→        arrivalDate?: string;
   987→      }>,
   988→      displayColor: row.displayColor ?? '#3B82F6',
   989→      // Detail-specific fields
   990→      changeHistory,
   991→      constraintValidation: {
   992→        isValid: violations.length === 0,
   993→        violations,
   994→        warnings,
   995→      },
   996→      assignedCrew: [] as Array<{
   997→        crewId: string;
   998→        crewName: string;
   999→        role: string;
  1000→        shift: string;
  1001→      }>,
  1002→    };
  1003→  });
  1004→
  1005→  return c.json(
  1006→    success(
  1007→      {
  1008→        pmBlocks,
  1009→        dateRange: {
  1010→          fromDate: fromDateStr,
  1011→          toDate: toDateStr,
  1012→        },
  1013→      },
  1014→      { timing: { durationMs: getRequestDuration(c) } }
  1015→    )
  1016→  );
  1017→});
